// Parse event metadata from the Promotix email subject line
// Subject format: "Guestlist for {EVENT_NAME}, {VENUE}, {STATE}, {DD} {Mon} {YY} {TIME}"
// Examples:
//   "Guestlist for ID COMEDY CLUB - FRI/SAT, Carousel, NSW, 27 Feb 26 7:00pm"
//   "Guestlist for MAGIC MIC COMEDY - Wednesdays, Potts Point Hotel, NSW, 25 Feb 26 7:30pm"

const subject = $json.subject || '';

// Remove the "Guestlist for " prefix
const afterPrefix = subject.replace(/^Guestlist for\s+/i, '');

// Parse from the END - the date/time pattern is always at the end
// Pattern: DD Mon YY H:MMam/pm
const dateTimeRegex = /(\d{1,2})\s+(Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)\s+(\d{2})\s+(\d{1,2}:\d{2}(?:am|pm))$/i;
const dateMatch = afterPrefix.match(dateTimeRegex);

let eventName = '';
let venue = '';
let state = '';
let eventDate = '';
let eventTime = '';

if (dateMatch) {
  const day = dateMatch[1].padStart(2, '0');
  const monthStr = dateMatch[2];
  const year = '20' + dateMatch[3];
  eventTime = dateMatch[4];

  // Convert month name to number
  const months = { Jan: '01', Feb: '02', Mar: '03', Apr: '04', May: '05', Jun: '06',
                    Jul: '07', Aug: '08', Sep: '09', Oct: '10', Nov: '11', Dec: '12' };
  const month = months[monthStr.charAt(0).toUpperCase() + monthStr.slice(1).toLowerCase()] || '01';
  eventDate = `${year}-${month}-${day}`;

  // Everything before the date match is "EVENT_NAME, VENUE, STATE, "
  const beforeDate = afterPrefix.substring(0, dateMatch.index).replace(/,\s*$/, '');

  // Split by comma - last part is state, second-to-last is venue, rest is event name
  const parts = beforeDate.split(',').map(p => p.trim());

  if (parts.length >= 3) {
    state = parts[parts.length - 1];
    venue = parts[parts.length - 2];
    eventName = parts.slice(0, parts.length - 2).join(', ');
  } else if (parts.length === 2) {
    venue = parts[1];
    eventName = parts[0];
  } else {
    eventName = parts[0] || afterPrefix;
  }
} else {
  // Fallback: can't parse date, use the whole thing as event name
  eventName = afterPrefix;
}

return {
  json: {
    ...$json,
    parsed_event_name: eventName,
    parsed_venue: venue,
    parsed_state: state,
    parsed_event_date: eventDate,
    parsed_event_time: eventTime
  }
};

// Parse the Promotix CSV attachment directly using helpers
// CSV columns: Order Number, Quantity, First Name, Surname, Email
// Quantity format: "2 General Admission" - extract the leading number
//
// Uses this.helpers.getBinaryDataBuffer() to access binary data
// (item.binary is not available in n8n Code node v2 task runner)

// Try common binary key names used by the IMAP trigger
let csvText = '';
const binaryKeys = ['attachment_0', 'attachment', 'data', 'attachment_1'];

for (const key of binaryKeys) {
  try {
    const buf = await this.helpers.getBinaryDataBuffer(0, key);
    if (buf && buf.length > 0) {
      csvText = buf.toString('utf-8');
      break;
    }
  } catch (e) {
    // Key not found, try next
  }
}

if (!csvText) {
  throw new Error('No CSV attachment found in Promotix email (tried keys: ' + binaryKeys.join(', ') + ')');
}

// Parse CSV
const lines = csvText.split('\n').map(l => l.trim()).filter(l => l.length > 0);

if (lines.length < 2) {
  throw new Error('CSV file is empty or has no data rows');
}

// Parse header
const header = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g, ''));
const orderIdx = header.findIndex(h => /order\s*number/i.test(h));
const qtyIdx = header.findIndex(h => /quantity/i.test(h));
const firstIdx = header.findIndex(h => /first\s*name/i.test(h));
const surnameIdx = header.findIndex(h => /surname|last\s*name/i.test(h));
const emailIdx = header.findIndex(h => /email/i.test(h));

// Get metadata from the parsed subject
const meta = $input.item.json;

const allRows = [];

for (let i = 1; i < lines.length; i++) {
  // Parse CSV line - handle quoted fields
  const fields = [];
  let current = '';
  let inQuotes = false;

  for (const char of lines[i]) {
    if (char === '"') {
      inQuotes = !inQuotes;
    } else if (char === ',' && !inQuotes) {
      fields.push(current.trim());
      current = '';
    } else {
      current += char;
    }
  }
  fields.push(current.trim());

  const orderNumber = orderIdx >= 0 ? (fields[orderIdx] || '').replace(/^"|"$/g, '') : '';
  const quantityRaw = qtyIdx >= 0 ? (fields[qtyIdx] || '').replace(/^"|"$/g, '') : '1';
  const firstName = firstIdx >= 0 ? (fields[firstIdx] || '').replace(/^"|"$/g, '') : '';
  const surname = surnameIdx >= 0 ? (fields[surnameIdx] || '').replace(/^"|"$/g, '') : '';
  const email = emailIdx >= 0 ? (fields[emailIdx] || '').replace(/^"|"$/g, '').toLowerCase() : '';

  // Parse ticket count from quantity string like "2 General Admission"
  const qtyMatch = quantityRaw.match(/^(\d+)/);
  const ticketCount = qtyMatch ? parseInt(qtyMatch[1], 10) : 1;

  // Skip rows without essential data
  if (!email) continue;

  allRows.push({
    json: {
      event_name: meta.parsed_event_name,
      venue: meta.parsed_venue,
      state: meta.parsed_state,
      event_date: meta.parsed_event_date,
      event_time: meta.parsed_event_time,
      first_name: firstName,
      last_name: surname,
      email: email,
      ticket_count: ticketCount,
      booking_reference: orderNumber,
      source_email_subject: meta.subject || '',
      source_email_date: meta.date || ''
    }
  });
}

if (allRows.length === 0) {
  throw new Error('No valid attendee rows found in Promotix CSV');
}

return allRows;

// Merge the parsed attendee data with the matched event/session
const attendee = $('Parse Promotix CSV').item.json;
const matchResult = $input.item.json;

// The RPC returns an array - take the first match
const match = Array.isArray(matchResult) ? matchResult[0] : matchResult;

if (!match || !match.event_id) {
  return {
    json: {
      ...attendee,
      event_id: null,
      session_id: null,
      match_status: 'no_match',
      match_message: `No event found matching: ${attendee.event_name} on ${attendee.event_date}`
    }
  };
}

return {
  json: {
    ...attendee,
    event_id: match.event_id,
    session_id: match.session_id || null,
    match_status: 'matched',
    match_message: `Matched to event: ${match.event_name || match.event_id}`
  }
};

// Prepare the final payload for manual_ticket_entries
const attendee = $('Merge Match Data').item.json;
const customerResult = $input.item.json;

// Get customer_id from upsert result
const customer = Array.isArray(customerResult) ? customerResult[0] : customerResult;
const customerId = customer?.id || null;

// Promotix Partner ID
const PROMOTIX_PARTNER_ID = '8a668f71-6282-46f5-822d-377ce92f8c58';

return {
  json: {
    event_id: attendee.event_id,
    session_id: attendee.session_id,
    partner_id: PROMOTIX_PARTNER_ID,
    ticket_count: attendee.ticket_count,
    gross_revenue: 0,
    commission_rate: 0,
    entry_date: attendee.event_date || new Date().toISOString().split('T')[0],
    first_name: attendee.first_name,
    last_name: attendee.last_name,
    email: attendee.email,
    booking_reference: attendee.booking_reference,
    customer_id: customerId,
    source: 'n8n',
    status: 'confirmed',
    notes: `Promotix import: ${attendee.event_name}`,
    reference_id: attendee.booking_reference
  }
};

// Handle results - log success/failure counts
const items = $input.all();
let inserted = 0;
let duplicates = 0;
let errors = 0;

for (const item of items) {
  const statusCode = item.json.statusCode || item.json?.headers?.status;
  if (statusCode === 201 || statusCode === 200) {
    inserted++;
  } else if (statusCode === 409) {
    duplicates++;
  } else {
    errors++;
  }
}

return {
  json: {
    summary: 'Promotix Import Complete',
    inserted: inserted,
    duplicates_skipped: duplicates,
    errors: errors,
    total_processed: items.length,
    timestamp: new Date().toISOString()
  }
};
